package org.elasticsearch.cluster.routing.allocation.allocator;

import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import org.elasticsearch.action.ActionListener;
import org.elasticsearch.cluster.metadata.IndexMetadata;
import org.elasticsearch.cluster.node.DiscoveryNode;
import org.elasticsearch.cluster.routing.RoutingNode;
import org.elasticsearch.cluster.routing.ShardRouting;
import org.elasticsearch.cluster.routing.allocation.AllocateUnassignedDecision;
import org.elasticsearch.cluster.routing.allocation.MoveDecision;
import org.elasticsearch.cluster.routing.allocation.RoutingAllocation;
import org.elasticsearch.cluster.routing.allocation.ShardAllocationDecision;
import org.elasticsearch.cluster.routing.allocation.WriteLoadForecaster;
import org.elasticsearch.cluster.routing.allocation.decider.AllocationDecider;
import org.elasticsearch.cluster.routing.allocation.decider.Decision;
import org.elasticsearch.common.settings.ClusterSettings;
import org.elasticsearch.common.settings.Setting;
import org.elasticsearch.common.settings.Setting.Property;
import org.elasticsearch.injection.guice.Inject;

/**
 * {@link PriorityShardsAllocator} is a decorator around {@link BalancedShardsAllocator} that adds
 * index-priority-aware shard placement.
 *
 * <p>Nodes can be annotated with a tier level via {@code node.attr.allocation_tier}. Indices whose
 * {@code index.priority} is at or above {@link #MIN_PRIORITY_FOR_TIERING_SETTING} will be
 * preferentially placed on nodes whose {@code allocation_tier} is at or above
 * {@link #MIN_NODE_TIER_SETTING}.
 *
 * <p>Allocation proceeds in two passes:
 * <ol>
 *   <li><b>Pass 1 (preferred)</b>: full allocation with tier constraints active. High-priority
 *       indices land on high-tier nodes when capacity allows.</li>
 *   <li><b>Pass 2 (fallback)</b>: if any high-priority shard remains unassigned after pass 1,
 *       tier constraints are relaxed and allocation retries. This ensures shards are never
 *       permanently stuck due to tier preference, preserving cluster health.</li>
 * </ol>
 *
 * <p>Hard constraints from {@link org.elasticsearch.cluster.routing.allocation.decider.DiskThresholdDecider},
 * {@link org.elasticsearch.cluster.routing.allocation.decider.AwarenessAllocationDecider}, and
 * {@link org.elasticsearch.cluster.routing.allocation.decider.FilterAllocationDecider} are always
 * respected and take precedence over tier preference.
 *
 * @see PriorityAllocationDecider
 * @see BalancedShardsAllocator
 */
public class PriorityShardsAllocator implements ShardsAllocator {

    private static final Logger logger = LogManager.getLogger(PriorityShardsAllocator.class);

    // -------------------------------------------------------------------------
    // Cluster-level settings
    // -------------------------------------------------------------------------

    /**
     * Master switch. When {@code false} this allocator behaves identically to
     * {@link BalancedShardsAllocator}.
     */
    public static final Setting<Boolean> PRIORITY_ALLOCATION_ENABLED_SETTING = Setting.boolSetting(
        "cluster.routing.allocation.priority.enabled",
        true,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Indices with {@code index.priority} >= this value are steered toward high-tier nodes.
     * Default: {@code 5}.
     */
    public static final Setting<Integer> MIN_PRIORITY_FOR_TIERING_SETTING = Setting.intSetting(
        "cluster.routing.allocation.priority.min_priority_for_tiering",
        5,
        1,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * The minimum {@code node.attr.allocation_tier} value considered a "high-tier" node.
     * Default: {@code 2} (i.e. SSD or better).
     */
    public static final Setting<Integer> MIN_NODE_TIER_SETTING = Setting.intSetting(
        "cluster.routing.allocation.priority.min_node_tier",
        2,
        1,
        Property.Dynamic,
        Property.NodeScope
    );

    // -------------------------------------------------------------------------
    // Fields
    // -------------------------------------------------------------------------

    /** Inner weight-based allocator that performs the actual shard balancing. */
    private final BalancedShardsAllocator delegate;

    private volatile boolean enabled;
    private volatile int minPriorityForTiering;
    private volatile int minNodeTier;

    // -------------------------------------------------------------------------
    // Constructor
    // -------------------------------------------------------------------------

    @Inject
    public PriorityShardsAllocator(ClusterSettings clusterSettings, WriteLoadForecaster writeLoadForecaster) {
        this(clusterSettings, new BalancedShardsAllocator(clusterSettings, writeLoadForecaster));
    }

    /**
     * Secondary constructor used in tests to inject a pre-built {@link BalancedShardsAllocator}.
     */
    public PriorityShardsAllocator(ClusterSettings clusterSettings, BalancedShardsAllocator delegate) {
        this.delegate = delegate;
        clusterSettings.initializeAndWatch(PRIORITY_ALLOCATION_ENABLED_SETTING, value -> this.enabled = value);
        clusterSettings.initializeAndWatch(MIN_PRIORITY_FOR_TIERING_SETTING, value -> this.minPriorityForTiering = value);
        clusterSettings.initializeAndWatch(MIN_NODE_TIER_SETTING, value -> this.minNodeTier = value);
    }

    // -------------------------------------------------------------------------
    // ShardsAllocator implementation
    // -------------------------------------------------------------------------

    /**
     * Allocates shards using a two-pass strategy:
     * <ol>
     *   <li>Pass 1: allocate with tier preferences enforced (via {@link PriorityAllocationDecider}).</li>
     *   <li>Pass 2: for any shard still unassigned, allocate without tier restrictions.</li>
     * </ol>
     */
    @Override
    public void allocate(RoutingAllocation allocation) {
        if (enabled == false) {
            // Feature disabled: fall straight through to the inner allocator.
            delegate.allocate(allocation);
            return;
        }

        // Pass 1: preferred placement — PriorityAllocationDecider is active.
        logger.debug("PriorityShardsAllocator: pass 1 — tier-aware allocation");
        delegate.allocate(allocation);

        // Pass 2: fallback — disable tier restrictions for remaining unassigned shards.
        if (allocation.routingNodes().unassigned().isEmpty() == false) {
            logger.warn(
                "PriorityShardsAllocator: {} shard(s) could not be placed on preferred tier; "
                    + "retrying without tier constraints (pass 2)",
                allocation.routingNodes().unassigned().size()
            );
            PriorityAllocationDecider.setFallbackMode(allocation, true);
            try {
                delegate.allocate(allocation);
            } finally {
                PriorityAllocationDecider.setFallbackMode(allocation, false);
            }
        }
    }

    @Override
    public void allocate(RoutingAllocation allocation, ActionListener<Void> listener) {
        allocate(allocation);
        listener.onResponse(null);
    }

    /**
     * Delegates explain decisions to the inner {@link BalancedShardsAllocator}.
     * {@link PriorityAllocationDecider} decisions appear automatically via {@code AllocationDeciders}.
     */
    @Override
    public ShardAllocationDecision decideShardAllocation(ShardRouting shard, RoutingAllocation allocation) {
        return delegate.decideShardAllocation(shard, allocation);
    }

    // =========================================================================
    // Inner class: PriorityAllocationDecider
    // =========================================================================

    /**
     * {@link PriorityAllocationDecider} steers high-priority index shards to high-tier nodes.
     *
     * <p>Node tier is read from the {@code node.attr.allocation_tier} attribute (default: {@code 1}).
     * Index priority is read from {@link IndexMetadata#INDEX_PRIORITY_SETTING} ({@code index.priority}).
     *
     * <p>This decider emits a soft NO when a high-priority index would be placed on a low-tier
     * node. The enclosing {@link PriorityShardsAllocator} overrides this NO in pass 2 (fallback).
     *
     * <p>Hard constraints ({@code DiskThresholdDecider}, {@code AwarenessAllocationDecider},
     * {@code FilterAllocationDecider}) run before this decider and are never overridden.
     */
    public static class PriorityAllocationDecider extends AllocationDecider {

        public static final String NAME = "priority";

        /**
         * Key used to signal fallback mode via {@link RoutingAllocation} custom state.
         * When set to {@code Boolean.TRUE} this decider returns {@link Decision#ALWAYS}.
         */
        private static final String FALLBACK_MODE_KEY = "priority_allocator_fallback";

        private volatile boolean enabled;
        private volatile int minPriorityForTiering;
        private volatile int minNodeTier;

        public PriorityAllocationDecider(ClusterSettings clusterSettings) {
            clusterSettings.initializeAndWatch(PRIORITY_ALLOCATION_ENABLED_SETTING, value -> this.enabled = value);
            clusterSettings.initializeAndWatch(MIN_PRIORITY_FOR_TIERING_SETTING, value -> this.minPriorityForTiering = value);
            clusterSettings.initializeAndWatch(MIN_NODE_TIER_SETTING, value -> this.minNodeTier = value);
        }

        /**
         * Returns a soft NO when a high-priority shard would land on a low-tier node,
         * unless fallback mode is active (pass 2 of the two-pass strategy).
         */
        @Override
        public Decision canAllocate(ShardRouting shardRouting, RoutingNode node, RoutingAllocation allocation) {
            if (enabled == false || isFallbackMode(allocation)) {
                return Decision.ALWAYS;
            }

            final IndexMetadata indexMetadata = allocation.metadata().getIndexSafe(shardRouting.index());
            final int indexPriority = indexMetadata.priority();

            if (indexPriority < minPriorityForTiering) {
                // Standard-priority index: no tier restriction.
                return Decision.ALWAYS;
            }

            final int nodeTier = getNodeTier(node.node());
            if (nodeTier < minNodeTier) {
                return allocation.decision(
                    Decision.NO,
                    NAME,
                    "index priority [%d] requires allocation_tier >= [%d], but node [%s] has allocation_tier [%d]",
                    indexPriority,
                    minNodeTier,
                    node.nodeId(),
                    nodeTier
                );
            }

            return Decision.ALWAYS;
        }

        /**
         * Shards already on a node are not forcibly evicted by priority tier changes.
         * Operators can trigger rebalancing explicitly via the Reroute API.
         */
        @Override
        public Decision canRemain(IndexMetadata indexMetadata, ShardRouting shardRouting, RoutingNode node, RoutingAllocation allocation) {
            return Decision.ALWAYS;
        }

        /**
         * Rebalancing across tiers is permitted, so that shards migrate to better-tiered nodes
         * when they become available.
         */
        @Override
        public Decision canRebalance(ShardRouting shardRouting, RoutingAllocation allocation) {
            return Decision.ALWAYS;
        }

        // ------------------------------------------------------------------
        // Fallback-mode helpers
        // ------------------------------------------------------------------

        /**
         * Activates or deactivates fallback mode on the given {@link RoutingAllocation}.
         * When active, this decider returns {@link Decision#ALWAYS} for all shards.
         */
        static void setFallbackMode(RoutingAllocation allocation, boolean fallback) {
            allocation.putCustomData(FALLBACK_MODE_KEY, fallback ? Boolean.TRUE : null);
        }

        private static boolean isFallbackMode(RoutingAllocation allocation) {
            return Boolean.TRUE.equals(allocation.getCustomData(FALLBACK_MODE_KEY));
        }

        // ------------------------------------------------------------------
        // Utility
        // ------------------------------------------------------------------

        /**
         * Reads the {@code allocation_tier} node attribute, defaulting to {@code 1} if absent
         * or unparseable.
         */
        private static int getNodeTier(DiscoveryNode node) {
            final String tierAttr = node.getAttributes().get("allocation_tier");
            if (tierAttr == null) {
                return 1;
            }
            try {
                final int tier = Integer.parseInt(tierAttr);
                return tier < 1 ? 1 : tier;
            } catch (NumberFormatException e) {
                logger.warn(
                    "Node [{}] has invalid allocation_tier attribute value [{}]; defaulting to 1",
                    node.getId(),
                    tierAttr
                );
                return 1;
            }
        }
    }
}

