121:     private volatile float threshold;
122: 
123:     private final WriteLoadForecaster writeLoadForecaster;
124: 
125:     public BalancedShardsAllocator() {
126:         this(Settings.EMPTY);
127:     }
128: 
129:     public BalancedShardsAllocator(Settings settings) {
130:         this(createBuiltInClusterSettings(settings), WriteLoadForecaster.DEFAULT);
131:     }
132: 
133:     public BalancedShardsAllocator(ClusterSettings clusterSettings) {
134:         this(clusterSettings, WriteLoadForecaster.DEFAULT);
135:     }
136: 
137:     @Inject
138:     public BalancedShardsAllocator(ClusterSettings clusterSettings, WriteLoadForecaster writeLoadForecaster) {
139:         clusterSettings.initializeAndWatch(SHARD_BALANCE_FACTOR_SETTING, value -> this.shardBalanceFactor = value);
140:         clusterSettings.initializeAndWatch(INDEX_BALANCE_FACTOR_SETTING, value -> this.indexBalanceFactor = value);
141:         clusterSettings.initializeAndWatch(WRITE_LOAD_BALANCE_FACTOR_SETTING, value -> this.writeLoadBalanceFactor = value);
142:         clusterSettings.initializeAndWatch(DISK_USAGE_BALANCE_FACTOR_SETTING, value -> this.diskUsageBalanceFactor = value);
143:         clusterSettings.initializeAndWatch(THRESHOLD_SETTING, value -> this.threshold = ensureValidThreshold(value));
144:         this.writeLoadForecaster = writeLoadForecaster;
145:     }
146: 
147:     /**
148:      * Clamp threshold to be at least 1, and log a critical deprecation warning if smaller values are given.
149:      *
150:      * Once {@link org.elasticsearch.Version#V_7_17_0} goes out of scope, start to properly reject such bad values.
151:      */
152:     @UpdateForV9
153:     private static float ensureValidThreshold(float threshold) {
154:         if (1.0f <= threshold) {
155:             return threshold;
156:         } else {
157:             DeprecationLogger.getLogger(BalancedShardsAllocator.class)
158:                 .critical(
159:                     DeprecationCategory.SETTINGS,
160:                     "balance_threshold_too_small",
161:                     "ignoring value [{}] for [{}] since it is smaller than 1.0; "
162:                         + "setting [{}] to a value smaller than 1.0 will be forbidden in a future release",
163:                     threshold,
164:                     THRESHOLD_SETTING.getKey(),
165:                     THRESHOLD_SETTING.getKey()
166:                 );
167:             return 1.0f;
168:         }
169:     }
170: 
171:     @Override
172:     public void allocate(RoutingAllocation allocation) {
173:         assert allocation.ignoreDisable() == false;
174: 
175:         if (allocation.routingNodes().size() == 0) {
176:             failAllocationOfNewPrimaries(allocation);
177:             return;
178:         }
179:         final WeightFunction weightFunction = new WeightFunction(
180:             shardBalanceFactor,
181:             indexBalanceFactor,
182:             writeLoadBalanceFactor,
183:             diskUsageBalanceFactor
184:         );
185:         final Balancer balancer = new Balancer(writeLoadForecaster, allocation, weightFunction, threshold);
186:         balancer.allocateUnassigned();
187:         balancer.moveShards();
188:         balancer.balance();
189:     }
