191:     @Override
192:     public ShardAllocationDecision decideShardAllocation(final ShardRouting shard, final RoutingAllocation allocation) {
193:         WeightFunction weightFunction = new WeightFunction(
194:             shardBalanceFactor,
195:             indexBalanceFactor,
196:             writeLoadBalanceFactor,
197:             diskUsageBalanceFactor
198:         );
199:         Balancer balancer = new Balancer(writeLoadForecaster, allocation, weightFunction, threshold);
200:         AllocateUnassignedDecision allocateUnassignedDecision = AllocateUnassignedDecision.NOT_TAKEN;
201:         MoveDecision moveDecision = MoveDecision.NOT_TAKEN;
202:         if (shard.unassigned()) {
203:             allocateUnassignedDecision = balancer.decideAllocateUnassigned(shard);
204:         } else {
205:             moveDecision = balancer.decideMove(shard);
206:             if (moveDecision.isDecisionTaken() && moveDecision.canRemain()) {
207:                 moveDecision = balancer.decideRebalance(shard, moveDecision.getCanRemainDecision());
208:             }
209:         }
210:         return new ShardAllocationDecision(allocateUnassignedDecision, moveDecision);
211:     }
