213:     private void failAllocationOfNewPrimaries(RoutingAllocation allocation) {
214:         RoutingNodes routingNodes = allocation.routingNodes();
215:         assert routingNodes.size() == 0 : routingNodes;
216:         final RoutingNodes.UnassignedShards.UnassignedIterator unassignedIterator = routingNodes.unassigned().iterator();
217:         while (unassignedIterator.hasNext()) {
218:             final ShardRouting shardRouting = unassignedIterator.next();
219:             final UnassignedInfo unassignedInfo = shardRouting.unassignedInfo();
220:             if (shardRouting.primary() && unassignedInfo.lastAllocationStatus() == AllocationStatus.NO_ATTEMPT) {
