package org.elasticsearch.cluster.routing.allocation.allocator;

import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import org.elasticsearch.action.ActionListener;
import org.elasticsearch.cluster.metadata.IndexMetadata;
import org.elasticsearch.cluster.node.DiscoveryNode;
import org.elasticsearch.cluster.routing.RoutingNode;
import org.elasticsearch.cluster.routing.ShardRouting;
import org.elasticsearch.cluster.routing.allocation.AllocateUnassignedDecision;
import org.elasticsearch.cluster.routing.allocation.MoveDecision;
import org.elasticsearch.cluster.routing.allocation.RoutingAllocation;
import org.elasticsearch.cluster.routing.allocation.ShardAllocationDecision;
import org.elasticsearch.cluster.routing.allocation.WriteLoadForecaster;
import org.elasticsearch.cluster.routing.allocation.decider.AllocationDecider;
import org.elasticsearch.cluster.routing.allocation.decider.Decision;
import org.elasticsearch.common.settings.ClusterSettings;
import org.elasticsearch.common.settings.Setting;
import org.elasticsearch.common.settings.Setting.Property;
import org.elasticsearch.injection.guice.Inject;

/**
 * {@link PriorityShardsAllocator} is a decorator around {@link BalancedShardsAllocator} that adds
 * index-priority-aware shard placement.
 *
 * <p>Nodes can be annotated with a tier level via {@code node.attr.allocation_tier}. Indices whose
 * {@code index.priority} is at or above {@link #MIN_PRIORITY_FOR_TIERING_SETTING} will be
 * preferentially placed on nodes whose {@code allocation_tier} is at or above
 * {@link #MIN_NODE_TIER_SETTING}.
 *
 * <p>Allocation proceeds in two passes:
 * <ol>
 *   <li><b>Pass 1 (preferred)</b>: full allocation with tier constraints active. High-priority
 *       indices land on high-tier nodes when capacity allows.</li>
 *   <li><b>Pass 2 (fallback)</b>: if any high-priority shard remains unassigned after pass 1,
 *       tier constraints are relaxed and allocation retries. This ensures shards are never
 *       permanently stuck due to tier preference, preserving cluster health.</li>
 * </ol>
 *
 * <p>Hard constraints from {@link org.elasticsearch.cluster.routing.allocation.decider.DiskThresholdDecider},
 * {@link org.elasticsearch.cluster.routing.allocation.decider.AwarenessAllocationDecider}, and
 * {@link org.elasticsearch.cluster.routing.allocation.decider.FilterAllocationDecider} are always
 * respected and take precedence over tier preference.
 *
 * @see PriorityAllocationDecider
 * @see BalancedShardsAllocator
 */
public class PriorityShardsAllocator implements ShardsAllocator {

    private static final Logger logger = LogManager.getLogger(PriorityShardsAllocator.class);

    // -------------------------------------------------------------------------
    // Cluster-level settings
    // -------------------------------------------------------------------------

    /**
     * Master switch. When {@code false} this allocator behaves identically to
     * {@link BalancedShardsAllocator}.
     */
    public static final Setting<Boolean> PRIORITY_ALLOCATION_ENABLED_SETTING = Setting.boolSetting(
        "cluster.routing.allocation.priority.enabled",
        true,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * Indices with {@code index.priority} >= this value are steered toward high-tier nodes.
     * Default: {@code 5}.
     */
    public static final Setting<Integer> MIN_PRIORITY_FOR_TIERING_SETTING = Setting.intSetting(
        "cluster.routing.allocation.priority.min_priority_for_tiering",
        5,
        1,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * The minimum {@code node.attr.allocation_tier} value considered a "high-tier" node.
     * Default: {@code 2} (i.e. SSD or better).
     */
    public static final Setting<Integer> MIN_NODE_TIER_SETTING = Setting.intSetting(
        "cluster.routing.allocation.priority.min_node_tier",
        2,
        1,
        Property.Dynamic,
        Property.NodeScope
    );

    // -------------------------------------------------------------------------
    // Fields
    // -------------------------------------------------------------------------

    /** Inner weight-based allocator that performs the actual shard balancing. */
    private final BalancedShardsAllocator delegate;

    private volatile boolean enabled;
    private volatile int minPriorityForTiering;
    private volatile int minNodeTier;

    // -------------------------------------------------------------------------
    // Constructor
    // -------------------------------------------------------------------------

    @Inject
    public PriorityShardsAllocator(ClusterSettings clusterSettings, WriteLoadForecaster writeLoadForecaster) {
        this(clusterSettings, new BalancedShardsAllocator(clusterSettings, writeLoadForecaster));
    }

    /**
     * Secondary constructor used in tests to inject a pre-built {@link BalancedShardsAllocator}.
     */
    public PriorityShardsAllocator(ClusterSettings clusterSettings, BalancedShardsAllocator delegate) {
        this.delegate = delegate;
        clusterSettings.initializeAndWatch(PRIORITY_ALLOCATION_ENABLED_SETTING, value -> this.enabled = value);
